function Player(name) {
  this.name = name;
}

// We attach a shared method to the constructor's prototype
Player.prototype.jump = function() {
  console.log(`${this.name} jumped!`);
};

// The 'new' keyword automatically links p1 to Player.prototype
const p1 = new Player('Mario');
p1.jump(); // 'Mario jumped!'

